from jinja2 import Template
def render_kpi(ctx):
    return Template("{{ region }}: {{ median }} PEN n={{ n }}").render(**ctx)
print(render_kpi({"region": "Lima", "median": 28, "n": 40}))

def render_outline(sections):
    return ["  " * (s["h"] - 1) + s["name"] for s in sections]
print(render_outline([{"name": "Resumen", "h": 1}, {"name": "Detalle", "h": 2}]))

def classify(chars, pages):
    return "needs_ocr" if chars / pages < 20 else "digital"
print(classify(100, 1))

def link_evidence(hid, table):
    return {"hallazgo": hid, "table": table}
print(link_evidence("H1", "Tabla1"))

def fmt_pen(x):
    return f"{round(x, 1)} PEN"
print(fmt_pen(28.04))

def a11y_min(has_h1, alts):
    return has_h1 and all(len(a) > 10 for a in alts)
print(a11y_min(True, ["Lima 28 PEN n=40", "short"]))
print(a11y_min(True, ["Lima 28 PEN n=40 detalle"]))

def ready(checklist):
    return all(checklist.values())
print(ready({"dashboard": True, "xlsx": True, "doc": True}))
